import { existsSync, readFileSync } from 'fs'
import { join } from 'path'
import { mkdirSync, writeFileSync } from 'fs'
import type { ProviderType } from '../types.js'

const BRIDGE_AI_MARKER = '<!-- bridge-ai generated -->'

/**
 * Check if a file was generated by bridge-ai (has our marker).
 */
function isBridgeAiGenerated(filePath: string): boolean {
  if (!existsSync(filePath)) return false
  try {
    const content = readFileSync(filePath, 'utf-8')
    return content.includes(BRIDGE_AI_MARKER)
  } catch {
    return false
  }
}

/**
 * Build a provider config file content from vault docs.
 * Reads vault markdown files and creates a condensed summary.
 */
function buildProviderContent(vaultPath: string, _projectRoot: string): string {
  const sections: string[] = [
    BRIDGE_AI_MARKER,
    '# Project Instructions',
    '',
    '> Auto-generated by bridge-ai from vault docs at `.bridgeai/vault/`',
    '> Re-run `/onboard` to regenerate.',
    '',
  ]

  // Read each doc file from vault and include its content
  const docFiles = [
    'overview.md',
    'stack.md',
    'architecture.md',
    'conventions.md',
    'testing.md',
    'commands.md',
  ]

  for (const docFile of docFiles) {
    const docPath = join(vaultPath, docFile)
    if (existsSync(docPath)) {
      try {
        const content = readFileSync(docPath, 'utf-8')
        sections.push(content)
        sections.push('')
      } catch {
        /* skip unreadable */
      }
    }
  }

  return sections.join('\n')
}

/**
 * Generate CLAUDE.md inside the vault directory.
 */
export function formatForClaude(
  vaultPath: string,
  projectRoot: string,
): { filePath: string; skipped: boolean; reason?: string } {
  const filePath = join(vaultPath, 'CLAUDE.md')

  const content = buildProviderContent(vaultPath, projectRoot)
  mkdirSync(vaultPath, { recursive: true })
  writeFileSync(filePath, content, 'utf-8')

  return { filePath, skipped: false }
}

/**
 * Generate .cursorrules at project root.
 */
export function formatForCursor(
  vaultPath: string,
  projectRoot: string,
): { filePath: string; skipped: boolean; reason?: string } {
  const filePath = join(projectRoot, '.cursorrules')

  // Check if file exists and is not ours
  if (existsSync(filePath) && !isBridgeAiGenerated(filePath)) {
    return {
      filePath,
      skipped: true,
      reason:
        'Existing .cursorrules not generated by bridge-ai — skipped to avoid overwriting manual edits',
    }
  }

  const content = buildProviderContent(vaultPath, projectRoot)
  writeFileSync(filePath, content, 'utf-8')
  return { filePath, skipped: false }
}

/**
 * Generate .gemini/rules.md at project root.
 */
export function formatForGemini(
  vaultPath: string,
  projectRoot: string,
): { filePath: string; skipped: boolean; reason?: string } {
  const geminiDir = join(projectRoot, '.gemini')
  const filePath = join(geminiDir, 'rules.md')

  if (existsSync(filePath) && !isBridgeAiGenerated(filePath)) {
    return {
      filePath,
      skipped: true,
      reason: 'Existing .gemini/rules.md not generated by bridge-ai — skipped',
    }
  }

  const content = buildProviderContent(vaultPath, projectRoot)
  mkdirSync(geminiDir, { recursive: true })
  writeFileSync(filePath, content, 'utf-8')
  return { filePath, skipped: false }
}

/**
 * Dispatch to the right formatter based on provider type.
 */
export function formatForProvider(
  provider: ProviderType,
  vaultPath: string,
  projectRoot: string,
): { filePath: string; skipped: boolean; reason?: string } {
  switch (provider) {
    case 'claude':
      return formatForClaude(vaultPath, projectRoot)
    case 'cursor':
      return formatForCursor(vaultPath, projectRoot)
    case 'gemini':
      return formatForGemini(vaultPath, projectRoot)
    case 'generic':
      return formatForClaude(vaultPath, projectRoot) // fallback to CLAUDE.md
  }
}
